fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len() as i64;
    let mut max_k = 0;

    for k in 0..=n {
        let mut arr = nums.clone();
        let mut visited = vec![false; n as usize];

        for i in 0..n {
            if visited[i as usize] {
                continue;
            }
            let mut found = false;
            for j in (i + 1)..n {
                if !visited[j as usize] && (arr[i as usize] & arr[j as usize]) == k {
                    arr[i as usize], arr[j as usize] = arr[j as usize], arr[i as usize];
                    visited[j as usize] = true;
                    found = true;
                    break;
                }
            }
            if !found {
                break;
            }
        }

        let sorted = (0..n).map(|i| i as i64).collect::<Vec<i64>>();
        if arr == sorted {
            max_k = max_k.max(k);
        }
    }

    max_k
}
